INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, 2, 1, 0, 1, "リリ", 40011, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 321, 125801, 24001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 2, 1, 0, 1, "クリア", 40011, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 322, 126001, 24001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (3, 2, 1, 0, 1, "プレシア", 40011, "んーと。\nこれ、あげる。\nはい", 323, 126101, 24001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (4, 2, 1, 0, 2, "リリ", 40011, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 324, 125801, 24001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (5, 2, 1, 0, 2, "クリア", 40011, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 325, 126001, 24001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (6, 2, 1, 0, 2, "プレシア", 40011, "お兄。\nきてくれて、うれしい", 326, 126101, 24001);
